const CLIP_RE = /\b(short|shorts|clip|clips|recorte|recortes|highlight|highlights|teaser|trailer|avance|snippet)\b|#shorts/i;
function isClip(podcastName, title, duration) {
  if (!skipClipsMap[podcastName]) return false;
  if (duration) {
    const parts = String(duration).split(':').map(Number);
    const secs = parts.length === 3 ? parts[0]*3600+parts[1]*60+parts[2] : parts.length === 2 ? parts[0]*60+parts[1] : parseInt(duration,10);
    if (secs > 0 && secs < 600) return true;
  }
  return CLIP_RE.test(title);
}

function parseDate(s) {
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return new Date(s + 'T00:00:00');
  const parts = s.split('/');
  const d = parts[0].padStart(2,'0'), m = parts[1].padStart(2,'0'), y = parts[2] || new Date().getFullYear();
  return new Date(`${y}-${m}-${d}T00:00:00`);
}

