  const dateRe = /(\d{4}-\d{2}-\d{2}|\d{1,2}\/\d{1,2}(?:\/\d{4})?)/g;
  const rawStr = raw_text || '';
  const matches = [...rawStr.matchAll(dateRe)];
  if (matches[0]) dateFrom = parseDate(matches[0][1]);
  if (matches[1]) dateTo = parseDate(matches[1][1]);
  if (!dateTo || dateTo > new Date()) dateTo = new Date();
  if (!dateFrom) {
    return [{json: {reply_text: 'Formato de fecha no reconocido.\n\nUsa:\n`/desde 2026-04-01`\n`/desde 2026-04-01 hasta 2026-04-10`\n`/desde 01/04/2026 hasta 10/04/2026 Nombre Podcast`', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
  }
}

// HTTP helper (fetch not available in n8n vm2 sandbox)
function httpGet(urlStr, redirects) {
  if (redirects === undefined) redirects = 5;
  return new Promise((resolve, reject) => {
    if (redirects < 0) return reject(new Error('too many redirects'));
    const https = require('https'), http = require('http');
    const lib = urlStr.startsWith('https') ? https : http;
    const req = lib.get(urlStr, {headers: {'User-Agent': 'PodcastBot/1.0'}}, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        res.resume();
        return resolve(httpGet(res.headers.location, redirects - 1));
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(Buffer.concat(chunks).toString()));
    });
    req.on('error', reject);
    req.setTimeout(10000, () => { req.destroy(new Error('timeout')); });
  });
}

// Fetch episodes from each podcast RSS/Atom feed
const allEpisodes = [];
for (const podcast of podcasts) {
  const feedUrl = podcast.rss_url || podcast.youtube_rss_url;
  try {
    const xml = await httpGet(feedUrl);
    // RSS: <item> tags
    const itemRe = /<item>([\s\S]*?)<\/item>/g;
    let m;
    while ((m = itemRe.exec(xml)) !== null) {
      const block = m[1];
      const get = (tag) => { const r = block.match(new RegExp('<' + tag + '[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/' + tag + '>')); return r ? r[1].trim() : ''; };
      const encMatch = block.match(/enclosure[^>]+url="([^"]+)"/);
      const pubRaw = get('pubDate') || get('published') || get('dc:date');
      const d = pubRaw ? new Date(pubRaw) : null;
      const epTitle = get('title') || 'Sin título';
      const epDur = get('itunes:duration') || null;
      if (!isClip(podcast.name, epTitle, epDur)) allEpisodes.push({
        podcast_name: podcast.name,
        title: epTitle,
        url: get('link') || (encMatch ? encMatch[1] : ''),
        pub_date: d ? d.toISOString() : null,
        pub_date_obj: d,
        description: get('description').replace(/<[^>]+>/g, '').slice(0, 150),
        duration: epDur
      });
    }
    // Atom: <entry> tags (YouTube feeds)
    const entryRe = /<entry>([\s\S]*?)<\/entry>/g;
    while ((m = entryRe.exec(xml)) !== null) {
      const block = m[1];
      const getA = (tag) => { const r = block.match(new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)<\\/' + tag + '>')); return r ? r[1].trim() : ''; };
      const linkM = block.match(/<link[^>]+href="([^"]+)"/);
      const pubRaw = getA('published') || getA('updated');
      const d = pubRaw ? new Date(pubRaw) : null;
      const atTitle = getA('title').replace(/<[^>]+>/g,'') || 'Sin título';
      if (!isClip(podcast.name, atTitle, null)) allEpisodes.push({
        podcast_name: podcast.name,
        title: atTitle,
        url: linkM ? linkM[1] : '',
        pub_date: d ? d.toISOString() : null,
        pub_date_obj: d,
        description: getA('summary').replace(/<[^>]+>/g, '').slice(0, 150),
        duration: null
      });
    }
  } catch(e) { /* skip failed feeds */ }
}

// Sort newest first
allEpisodes.sort((a, b) => (b.pub_date_obj || 0) - (a.pub_date_obj || 0));

// Apply filters
let filtered = allEpisodes;
if (episodes_action === 'browse_range') {
  filtered = allEpisodes.filter(ep => ep.pub_date_obj && ep.pub_date_obj >= dateFrom && ep.pub_date_obj <= dateTo);
}
// For browse/bulk_add: don't slice yet — slice AFTER seen filter so N means N new episodes

if (!filtered.length) {
  const msg = episodes_action === 'browse_range'
    ? 'No encontré episodios en ese rango de fechas.'
    : 'No encontré episodios en los feeds. ¿Tienes RSS configurado? Revisa con /podcasts.';
  return [{json: {reply_text: msg, reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

// BULK ADD
if (episodes_action === 'bulk_add') {
  // Apply count limit after seen filter
  const limit = episode_count || 5;
  filtered = filtered.filter(ep => !queuedTitles.has(ep.title)).slice(0, limit);
  const added = [];
  for (const ep of filtered) {
    const dup = queue.items.find(i => i.title === ep.title && i.status === 'pending');
    if (!dup) {
      queue.items.push({
        id: 'q' + Date.now().toString(36).slice(-8) + Math.random().toString(36).slice(-3),
        title: ep.title, podcast: ep.podcast_name, url: ep.url,
        duration_min: null, source: 'bulk_add',
        added_at: new Date().toISOString(), status: 'pending', rating: null
      });
      added.push(ep);
    }
  }
  fs.writeFileSync(queuePath, JSON.stringify(queue, null, 2));
  if (!added.length) return [{json: {reply_text: 'Todos los episodios ya estaban en tu lista.', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
  let text = `✅ *${added.length} episodio${added.length > 1 ? 's' : ''} añadidos a tu lista*\n\n`;
  added.forEach((ep, i) => { text += `${i+1}. *${ep.podcast_name}* — ${ep.title}\n`; });
  return [{json: {reply_text: text, reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

// BROWSE / BROWSE_RANGE: one message per episode with ✅/❌ buttons
// (seenKeys and queuedTitles defined earlier)

// Apply count limit AFTER seen filter so N means N unseen episodes
const browseLimit = episode_count || 5;
