  if (seenKeys.has(seenKey) || queuedTitles.has(ep.title)) continue;
  browseCount++;
  const episode_id = 'eb' + Date.now().toString(36).slice(-6) + (counter++).toString(36);
  browseCache[episode_id] = {title: ep.title, podcast: ep.podcast_name, url: ep.url, duration_min: null, pub_date: ep.pub_date};
  const dateStr = ep.pub_date_obj ? ep.pub_date_obj.toLocaleDateString('es-ES', {day:'numeric', month:'short'}) : '';
  const dur = ep.duration ? ` · ${ep.duration}` : '';
  let text = `🎙️ *${ep.podcast_name}*\n_${ep.title}${dur}_`;
  if (dateStr) text += ` · ${dateStr}`;
  if (ep.description) text += `\n${ep.description}`;
  if (ep.url) text += `\n🔗 ${ep.url}`;
  result.push({json: {
    reply_text: text,
    reply_markup: JSON.stringify({inline_keyboard: [[
      {text: '✅ Añadir', callback_data: `q_add:${episode_id}`},
      {text: '❌ Saltar', callback_data: `eb_skip:${episode_id}`}
    ]]}),
    callback_query_id: null,
    answer_text: null
  }});
}
fs.writeFileSync(cachePath, JSON.stringify(browseCache, null, 2));
return result;

