    while ((m = itemRe.exec(xml)) !== null) {
      const block = m[1];
      const get = (tag) => { const r = block.match(new RegExp('<'+tag+'[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\/'+tag+'>')); return r ? r[1].trim() : ''; };
      const encM = block.match(/enclosure[^>]+url="([^"]+)"/);
      const pubRaw = get('pubDate') || get('published');
      const d = pubRaw ? new Date(pubRaw) : null;
      if (!d || d < cutoff) continue;
      const title = get('title') || 'Sin título';
      const dur = get('itunes:duration') || null;
      if (isClip(podcast.name, title, dur)) continue;
      const sk = podcast.name + '||' + title;
      if (seenKeys.has(sk) || queuedTitles.has(title)) continue;
      allEpisodes.push({podcast_name: podcast.name, title, url: get('link')||(encM?encM[1]:''), pub_date: d.toISOString(), description: get('description').replace(/<[^>]+>/g,'').slice(0,200), duration: dur});
    }
    const entryRe = /<entry>([\s\S]*?)<\/entry>/g;
    while ((m = entryRe.exec(xml)) !== null) {
      const block = m[1];
      const getA = (tag) => { const r = block.match(new RegExp('<'+tag+'[^>]*>([\\s\\S]*?)<\/'+tag+'>')); return r ? r[1].trim() : ''; };
      const linkM = block.match(/<link[^>]+href="([^"]+)"/);
      const pubRaw = getA('published') || getA('updated');
      const d = pubRaw ? new Date(pubRaw) : null;
      if (!d || d < cutoff) continue;
      const title = getA('title').replace(/<[^>]+>/g,'') || 'Sin título';
      if (isClip(podcast.name, title, null)) continue;
      const sk = podcast.name + '||' + title;
      if (seenKeys.has(sk) || queuedTitles.has(title)) continue;
      allEpisodes.push({podcast_name: podcast.name, title, url: linkM?linkM[1]:'', pub_date: d.toISOString(), description: getA('summary').replace(/<[^>]+>/g,'').slice(0,200), duration: null});
    }
  } catch(e) {}
}

if (!allEpisodes.length) {
  return [{json: {reply_text: '😕 No encontré episodios nuevos para recomendar. Prueba en unos días o añade más podcasts con /follow.', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

allEpisodes.sort((a, b) => new Date(b.pub_date) - new Date(a.pub_date));
const candidates = allEpisodes.slice(0, 40);

let ratingsStr = 'Sin valoraciones aún.';
try {
  const rh = JSON.parse(fs.readFileSync('/data/ratings_history.json', 'utf8'));
  const recent = (rh.ratings || []).slice(-10);
  if (recent.length) ratingsStr = recent.map(r => `- "${r.title}" → ${r.rating}★`).join('\n');
} catch(e) {}

const skippedStr = skippedItems.length
  ? skippedItems.map(i => `- "${i.title}" (${i.podcast || ''})`).join('\n')
  : 'Ninguno.';

const episodeList = candidates.map((ep, i) => {
  const d = new Date(ep.pub_date).toLocaleDateString('es-ES', {day:'numeric', month:'short'});
  return `${i+1}. [${ep.podcast_name}] "${ep.title}" (${d})${ep.description ? '\n   '+ep.description.slice(0,120) : ''}`;
}).join('\n\n');

const prompt = `Eres un recomendador de podcasts. Selecciona exactamente ${count} episodios de la lista que más le gustarán al usuario según su historial.\n\nVALORACIONES RECIENTES (positivo = le gustó, negativo = no):\n${ratingsStr}\n\nEPISODIOS SALTADOS RECIENTEMENTE (no recomendar estos ni similares):\n${skippedStr}\n\nEPISODIOS DISPONIBLES:\n${episodeList}\n\nResponde SOLO con JSON válido, sin texto extra:\n[{"idx": 1, "reason": "frase corta máx 80 chars"}, ...]\n\nElige ${count} episodios distintos. Evita recomendar episodios similares a los saltados.`;

let picks = [];
try {
  const resp = await httpPost('https://api.anthropic.com/v1/messages', {'x-api-key': $env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01'}, {model: 'claude-sonnet-4-5', max_tokens: 600, messages: [{role: 'user', content: prompt}]});
  const text = resp.content?.[0]?.text || '';
  const jm = text.match(/\[[\s\S]*\]/);
  if (jm) picks = JSON.parse(jm[0]);
} catch(e) {
  return [{json: {reply_text: '❌ Error al generar recomendaciones. Inténtalo de nuevo.', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

if (!picks.length) return [{json: {reply_text: '😕 No pude generar recomendaciones ahora. Inténtalo de nuevo.', reply_markup: null, callback_query_id: cbId, answer_text: null}}];

const result = [];
let counter = 0;
for (const pick of picks.slice(0, count)) {
  const ep = candidates[(pick.idx || 1) - 1];
  if (!ep) continue;
  const episode_id = 'eb' + Date.now().toString(36).slice(-6) + (counter++).toString(36);
  browseCache[episode_id] = {title: ep.title, podcast: ep.podcast_name, url: ep.url, duration_min: null};
  const d = new Date(ep.pub_date).toLocaleDateString('es-ES', {day:'numeric', month:'short'});
  const header = counter === 1 ? `🎯 *${count} recomendaciones para ti*\n\n` : '';
  const text = `${header}🎙 *${ep.podcast_name}*\n_${ep.title}_ · ${d}\n\n💡 ${pick.reason}${ep.url ? '\n🔗 '+ep.url : ''}`;
  result.push({json: {reply_text: text, reply_markup: JSON.stringify({inline_keyboard: [[{text: '✅ Añadir', callback_data: `q_add:${episode_id}`},{text: '❌ Saltar', callback_data: `eb_skip:${episode_id}`}]]}), callback_query_id: null, answer_text: null}});
}
fs.writeFileSync(cachePath, JSON.stringify(browseCache, null, 2));
return result;

const fs = require('fs');
const profile = JSON.parse(fs.readFileSync('/data/user_profile.json', 'utf8'));
let ratings = {ratings: [], proactive_reports: []};
try { ratings = JSON.parse(fs.readFileSync('/data/ratings_history.json', 'utf8')); } catch(e) {}
let queue = {items: []};
try { queue = JSON.parse(fs.readFileSync('/data/podcast_queue.json', 'utf8')); } catch(e) {}

// Podcasts seguidos
const podcasts = profile.known_podcasts || [];
const podcastLines = podcasts.map(p => {
  const fb = p.feedback || {};
  const score = fb.topic_score != null ? ` · tema ${fb.topic_score}/10` : '';
  const host = fb.host_score != null ? ` · host ${fb.host_score}/10` : '';
  const likes = fb.quick_likes > 0 ? ` · 👍×${fb.quick_likes}` : '';
  const dislikes = fb.quick_dislikes > 0 ? ` · 👎×${fb.quick_dislikes}` : '';
  const rated = fb.episodes_rated > 0 ? ` · ${fb.episodes_rated} ep. valorados` : '';
