  return `• *${p.name}* (prioridad ${p.priority || 6})${score}${host}${likes}${dislikes}${rated}${why}`;
}).join('\n');

// Intereses/temas
const interests = profile.interests || {};
const interestLines = Object.entries(interests).sort((a,b) => b[1]-a[1]).map(([k,v]) => `• ${k}: ${v}/10`).join('\n');

// Host affinities
const hosts = profile.host_affinities || {};
const hostLines = Object.entries(hosts).sort((a,b) => b[1]-a[1]).map(([k,v]) => `• ${k}: ${v}/10`).join('\n');

// Episodios escuchados (queue)
const listened = (queue.items || []).filter(i => i.status === 'listened').slice(-10).reverse();
const listenedLines = listened.length
  ? listened.map(i => {
      const stars = i.rating != null ? ' · ' + '⭐'.repeat(i.rating || 0) + (i.rating === 0 ? '0⭐' : '') : '';
      const date = i.listened_at ? new Date(i.listened_at).toLocaleDateString('es-ES', {day:'numeric', month:'short'}) : '';
      return `• *${i.title}* ${i.podcast ? '_('+i.podcast+')_' : ''}${stars}${date ? ' · '+date : ''}`;
    }).join('\n')
  : '_Ninguno aún_';

// Reportes proactivos
const reports = (ratings.proactive_reports || []).slice(-5).reverse();
const reportLines = reports.length
  ? reports.map(r => {
      const s = r.data?.sentiment === 'positive' ? '👍' : r.data?.sentiment === 'negative' ? '👎' : '😐';
      const date = r.timestamp ? new Date(r.timestamp).toLocaleDateString('es-ES', {day:'numeric', month:'short'}) : '';
      return `${s} *${r.data?.name || '?'}*${date ? ' · '+date : ''}${r.report_summary ? '\n  _'+r.report_summary+'_' : ''}`;
    }).join('\n')
  : '_Ninguno aún_';

// Valoraciones rápidas recientes
const recentRatings = (ratings.ratings || []).slice(-5).reverse();
const ratingLines = recentRatings.length
  ? recentRatings.map(r => {
      const stars = r.rating != null ? '⭐'.repeat(r.rating) || '0⭐' : r.action === 'like' ? '👍' : '👎';
      return `${stars} _${r.title || r.item_id}_`;
    }).join('\n')
  : '_Ninguna aún_';

let msg = `👤 *Tu perfil de gustos*\n\n`;
msg += `📻 *Podcasts seguidos* (${podcasts.length})\n${podcastLines || '_Ninguno_'}\n`;
if (interestLines) msg += `\n🏷 *Temas de interés*\n${interestLines}\n`;
if (hostLines) msg += `\n🎙 *Presentadores favoritos*\n${hostLines}\n`;
msg += `\n✅ *Episodios escuchados recientemente* (últimos 10)\n${listenedLines}\n`;
msg += `\n💬 *Lo que me has contado* (últimos 5)\n${reportLines}\n`;
msg += `\n⭐ *Valoraciones recientes*\n${ratingLines}`;

// Telegram has 4096 char limit per message
if (msg.length > 4000) msg = msg.slice(0, 3990) + '\n_[truncado]_';

return [{json: {reply_text: msg, reply_markup: null, callback_query_id: null, answer_text: null}}];

const fs = require('fs');
const inp = $input.first().json;
const searchTitle = inp.queue_title || '';
const podcastFilter = inp.queue_podcast || '';
const cbId = inp.callback_query_id || null;

const profilePath = '/data/user_profile.json';
const queuePath = '/data/podcast_queue.json';
const cachePath = '/data/episode_browse_cache.json';
const profile = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
let queue = {items: []};
try { queue = JSON.parse(fs.readFileSync(queuePath, 'utf8')); } catch(e) {}
let browseCache = {};
try { browseCache = JSON.parse(fs.readFileSync(cachePath, 'utf8')); } catch(e) {}

function httpGet(urlStr, redirects) {
  if (redirects === undefined) redirects = 5;
  return new Promise((resolve, reject) => {
    if (redirects < 0) return reject(new Error('too many redirects'));
    const https = require('https'), http = require('http');
    const lib = urlStr.startsWith('https') ? https : http;
    const req = lib.get(urlStr, {headers: {'User-Agent': 'PodcastBot/1.0'}}, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        res.resume();
        return resolve(httpGet(res.headers.location, redirects - 1));
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(Buffer.concat(chunks).toString()));
    });
    req.on('error', reject);
    req.setTimeout(12000, () => { req.destroy(new Error('timeout')); });
  });
}

function normalize(s) {
  return s.toLowerCase().replace(/[^\w\s]/g, ' ').replace(/\s+/g, ' ').trim();
}

function matchScore(query, candidate) {
  const qWords = normalize(query).split(' ').filter(w => w.length > 2);
  if (!qWords.length) return 0;
  const cNorm = normalize(candidate);
  return qWords.filter(w => cNorm.includes(w)).length / qWords.length;
}

function parseXml(xml, podcast) {
  const results = [];
  const itemRe = /<item>([\s\S]*?)<\/item>/g;
  let m;
  while ((m = itemRe.exec(xml)) !== null) {
    const block = m[1];
    const get = (tag) => { const r = block.match(new RegExp('<'+tag+'[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/'+tag+'>')); return r ? r[1].trim() : ''; };
    const encM = block.match(/enclosure[^>]+url="([^"]+)"/);
    const epTitle = get('title') || '';
    const sc = matchScore(searchTitle, epTitle);
    if (sc < 0.4) continue;
    const durRaw = get('itunes:duration');
    let dur_min = null;
    if (durRaw) { const p = durRaw.split(':').map(Number); const s = p.length===3?p[0]*3600+p[1]*60+p[2]:p.length===2?p[0]*60+p[1]:parseInt(durRaw,10); if (s>0) dur_min = Math.round(s/60); }
    results.push({title: epTitle, podcast: podcast.name, url: get('link')||(encM?encM[1]:''), pub_date: get('pubDate'), duration_min: dur_min, score: sc});
  }
  const entryRe = /<entry>([\s\S]*?)<\/entry>/g;
  while ((m = entryRe.exec(xml)) !== null) {
    const block = m[1];
    const getA = (tag) => { const r = block.match(new RegExp('<'+tag+'[^>]*>([\\s\\S]*?)<\\/'+tag+'>')); return r ? r[1].replace(/<[^>]+>/g,'').trim() : ''; };
    const linkM = block.match(/<link[^>]+href="([^"]+)"/);
    const epTitle = getA('title') || '';
    const sc = matchScore(searchTitle, epTitle);
    if (sc < 0.4) continue;
    results.push({title: epTitle, podcast: podcast.name, url: linkM?linkM[1]:'', pub_date: getA('published')||getA('updated'), duration_min: null, score: sc});
  }
  return results;
}

function saveListened(ep) {
  const newItem = {
    id: 'q' + Date.now().toString(36).slice(-8),
    title: ep.title, podcast: ep.podcast || '', url: ep.url || '',
    duration_min: ep.duration_min || null, source: 'manual_listened',
    added_at: new Date().toISOString(), status: 'listened',
    listened_at: new Date().toISOString(), rating: null
  };
  queue.items.push(newItem);
  fs.writeFileSync(queuePath, JSON.stringify(queue, null, 2));
  return newItem;
}

function ratingKeyboard(itemId) {
  return {inline_keyboard: [[
    {text:'0⭐',callback_data:`q_rate:${itemId}:0`},
    {text:'1⭐',callback_data:`q_rate:${itemId}:1`},
    {text:'2⭐',callback_data:`q_rate:${itemId}:2`},
    {text:'3⭐',callback_data:`q_rate:${itemId}:3`},
    {text:'4⭐',callback_data:`q_rate:${itemId}:4`},
    {text:'5⭐',callback_data:`q_rate:${itemId}:5`}
  ]]};
}

let podcasts = profile.known_podcasts || [];
if (podcastFilter) {
  const filtered = podcasts.filter(p => normalize(p.name).includes(normalize(podcastFilter)));
  if (filtered.length) podcasts = filtered;
}

const candidates = [];
for (const podcast of podcasts) {
  const feedUrl = podcast.rss_url || podcast.youtube_rss_url;
  if (!feedUrl) continue;
  try {
    const xml = await httpGet(feedUrl);
    candidates.push(...parseXml(xml, podcast));
  } catch(e) {}
}
candidates.sort((a,b) => b.score - a.score);
const top = candidates.slice(0, 3);

// No match
if (!top.length) {
  const item = saveListened({title: searchTitle, podcast: podcastFilter});
  return [{json: {reply_text: `✅ *${searchTitle}*${podcastFilter ? '\n_' + podcastFilter + '_' : ''}\n\n_No encontré el episodio en los feeds, guardado tal cual._\n\n¿Cuánto te ha gustado? (0–5)`, reply_markup: JSON.stringify(ratingKeyboard(item.id)), callback_query_id: cbId, answer_text: null}}];
}

// Clear match (>85% o único)
if (top.length === 1 || top[0].score >= 0.85) {
  const ep = top[0];
  const item = saveListened(ep);
  const dur = ep.duration_min ? ` · ${ep.duration_min}min` : '';
  const date = ep.pub_date ? ' · ' + new Date(ep.pub_date).toLocaleDateString('es-ES',{day:'numeric',month:'short'}) : '';
  return [{json: {reply_text: `✅ *${ep.title}*\n_${ep.podcast}${dur}${date}_\n\n¿Cuánto te ha gustado? (0–5)`, reply_markup: JSON.stringify(ratingKeyboard(item.id)), callback_query_id: cbId, answer_text: null}}];
}

// Múltiples — mostrar opciones
const ts = Date.now().toString(36);
const rows = top.map((ep, i) => {
  const epId = `sl${ts}${i}`;
  browseCache[epId] = ep;
  const dur = ep.duration_min ? ` ${ep.duration_min}min` : '';
  return [{text: `${ep.podcast} — ${ep.title.slice(0,32)}${dur}`, callback_data: `sl_pick:${epId}`}];
});
// "ninguno" option: encode title in id (max ~40 chars for callback_data budget)
const noneId = `sln${ts}`;
browseCache[noneId] = {title: searchTitle, podcast: podcastFilter};
rows.push([{text: '❌ Ninguno (guardar como escribí)', callback_data: `sl_pick:${noneId}`}]);
fs.writeFileSync(cachePath, JSON.stringify(browseCache, null, 2));

const matchList = top.map((ep,i) => `${i+1}. *${ep.title}*\n   _${ep.podcast}${ep.duration_min?' · '+ep.duration_min+'min':''}_`).join('\n\n');
return [{json: {reply_text: `🔍 Encontré varios episodios. ¿Cuál es?\n\n${matchList}`, reply_markup: JSON.stringify({inline_keyboard: rows}), callback_query_id: cbId, answer_text: null}}];

const { Pool } = require('pg');
const pool = new Pool({
  host: $env.POSTGRES_HOST || 'postgres_shared',
  port: parseInt($env.POSTGRES_PORT || '5432'),
  database: $env.POSTGRES_DB || 'homelab',
  user: $env.POSTGRES_USER,
  password: $env.POSTGRES_PASSWORD,
});
const srcIcon = s => s === 'youtube' ? '📺' : s === 'article' ? '📰' : '🎙';

const inp = $input.first().json;
const cbId = inp.callback_query_id || null;
const action = inp.action || '';
const id = inp.item_id || '';

function R(text, markup, answerText) {
  return [{json: {reply_text: text || null, reply_markup: markup || null, callback_query_id: cbId, answer_text: answerText || null}}];
}

try {
  if (action === 'mark_listened') {
    await pool.query(
      `UPDATE podcasts.episodes SET status='listened', listened_at=NOW() WHERE id=$1`, [id]
    );
    await pool.end();
    return R('✅ Marcado como escuchado.', null, '✅');
  }

  if (action === 'delete_episode') {
    const { rows } = await pool.query(`SELECT title FROM podcasts.episodes WHERE id=$1`, [id]);
    await pool.end();
    const title = (rows[0]?.title || 'este episodio').slice(0, 40);
    const markup = JSON.stringify({inline_keyboard: [[
      {text: 'Sí, borrar', callback_data: `confirm_delete:${id}`},
      {text: 'Cancelar',   callback_data: `cancel_delete:${id}`}
    ]]});
    return R(`🗑 ¿Eliminar *"${title}"*?`, markup, null);
  }

  if (action === 'confirm_delete') {
    await pool.query(`UPDATE podcasts.episodes SET status='dismissed' WHERE id=$1`, [id]);
    await pool.end();
    return R('🗑 Episodio eliminado.', null, '🗑');
  }

  if (action === 'cancel_delete') {
    await pool.end();
    return R(null, null, 'Cancelado');
  }

  if (action === 'rate_episode') {
    const { rows } = await pool.query(`SELECT title, rating FROM podcasts.episodes WHERE id=$1`, [id]);
    await pool.end();
    const current = rows[0]?.rating ? ` (actual: ${rows[0].rating}★)` : '';
    const stars = [1, 2, 5].map(n => ({
      text: `${n}★`,
      callback_data: `set_rating:${id}:${n}`
    }));
    return R(`⭐ *Valorar*${current}`, JSON.stringify({inline_keyboard: [stars]}), null);
  }

  if (action === 'set_rating') {
    const lastColon = id.lastIndexOf(':');
    const episodeId = id.slice(0, lastColon);
    const stars = parseInt(id.slice(lastColon + 1), 10);
    await pool.query(`UPDATE podcasts.episodes SET rating=$1 WHERE id=$2`, [stars, episodeId]);
    await pool.end();
    return R(`${'⭐'.repeat(stars)} Guardado.`, null, '⭐'.repeat(stars));
  }

  if (action === 'edit_note') {
    await pool.end();
    const staticData = $getWorkflowStaticData('global');
    staticData.waiting_note = id;
    return R('✏️ *Escribe tu nota ahora* (responde a este mensaje):', JSON.stringify({force_reply: true, selective: true}), null);
  }

  if (action === 'lista_page') {
    const page = parseInt(id, 10) || 1;
    const { rows } = await pool.query(
      `SELECT id, source, title, show_name, duration_min, url
       FROM podcasts.episodes
       WHERE status IN ('pending','skipped')
       ORDER BY created_at DESC`
    );
    await pool.end();
    if (!rows.length) return R('📋 *Tu lista está vacía*', null, null);
    const PAGE_SIZE = 10;
    const totalPages = Math.max(1, Math.ceil(rows.length / PAGE_SIZE));
    const cur = Math.max(1, Math.min(page, totalPages));
    const slice = rows.slice((cur - 1) * PAGE_SIZE, cur * PAGE_SIZE);
    const inline_keyboard = [];
    for (const r of slice) {
      const dur = r.duration_min ? ` (${r.duration_min}min)` : '';
      const label = `${srcIcon(r.source)} ${r.title.slice(0, 30)}${r.title.length > 30 ? '…' : ''}${dur}`;
      inline_keyboard.push([{text: label, callback_data: 'noop'}]);
      const actionRow = [
        {text: '✅ Escuchado', callback_data: `mark_listened:${r.id}`},
        {text: '🗑 Eliminar',  callback_data: `delete_episode:${r.id}`},
        {text: '✏️ Nota',      callback_data: `edit_note:${r.id}`}
      ];
      if (r.url) actionRow.push({text: '🔗', url: r.url});
      inline_keyboard.push(actionRow);
    }
    const navRow = [];
    if (cur > 1)          navRow.push({text: '← Anterior',  callback_data: `lista_page:${cur - 1}`});
    navRow.push({text: `${cur}/${totalPages}`, callback_data: 'noop'});
    if (cur < totalPages) navRow.push({text: 'Siguiente →', callback_data: `lista_page:${cur + 1}`});
    if (navRow.length > 1) inline_keyboard.push(navRow);
    const headerText = `📋 *Tu lista* — ${rows.length} ep. · Página ${cur}/${totalPages}`;
    return [{json: {reply_text: headerText, reply_markup: JSON.stringify({inline_keyboard}), callback_query_id: cbId, answer_text: null}}];
  }

  if (action === 'eplist_page') {
    const page = parseInt(id, 10) || 1;
    const { rows: epRows } = await pool.query(
      `SELECT id, source, title, show_name, rating, listened_at, url
       FROM podcasts.episodes WHERE status='listened'
       ORDER BY listened_at DESC NULLS LAST`
    );
    await pool.end();
    if (!epRows.length) return R('✅ No hay episodios escuchados.', null, null);
    const PAGE_SIZE = 8;
    const totalPages = Math.max(1, Math.ceil(epRows.length / PAGE_SIZE));
    const cur = Math.max(1, Math.min(page, totalPages));
    const slice = epRows.slice((cur - 1) * PAGE_SIZE, cur * PAGE_SIZE);
    const ik = [];
    for (const r of slice) {
      const date = r.listened_at ? new Date(r.listened_at).toLocaleDateString('es-ES', {day:'numeric',month:'short'}) : '';
      const stars = r.rating ? ' ' + '⭐'.repeat(parseInt(r.rating)) : '';
      const label = `${srcIcon(r.source)} ${r.title.slice(0,28)}${r.title.length>28?'…':''}${date?' · '+date:''}${stars}`;
      ik.push([{text: label, callback_data: 'noop'}]);
      const actionRow = [
