const fs = require('fs');
const https = require('https');
const { Pool } = require('pg');
const inp = $input.first().json;
const cbId = inp.callback_query_id || null;
const tokenPath = '/data/spotify_token.json';

function R(text) {
  return [{json: {reply_text: text, reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

let tokenData;
try { tokenData = JSON.parse(fs.readFileSync(tokenPath, 'utf8')); }
catch(e) { return R('❌ No hay token de Spotify. Ejecuta: `bash scripts/spotify_auth.sh`'); }

async function spotifyGet(path, token) {
  return new Promise((resolve, reject) => {
    const req = https.get(`https://api.spotify.com/v1${path}`,
      {headers: {Authorization: `Bearer ${token}`}}, res => {
        let data = '';
        res.on('data', c => data += c);
        res.on('end', () => {
          try { resolve({status: res.statusCode, body: JSON.parse(data)}); }
          catch(e) { resolve({status: res.statusCode, body: {}}); }
        });
      });
    req.on('error', reject);
    req.setTimeout(10000, () => req.destroy(new Error('timeout')));
  });
}

// Refresh token if expired
if (tokenData.expires_at && Date.now() >= tokenData.expires_at - 60000) {
  const clientId = $env.SPOTIFY_CLIENT_ID;
  const params = new URLSearchParams({
    grant_type: 'refresh_token',
    refresh_token: tokenData.refresh_token,
    client_id: clientId
  });
  const refreshResult = await new Promise((resolve, reject) => {
    const body = params.toString();
    const req = https.request({
      hostname: 'accounts.spotify.com', path: '/api/token', method: 'POST',
      headers: {'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': Buffer.byteLength(body)}
    }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => resolve(JSON.parse(d)));
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
  if (refreshResult.access_token) {
    tokenData.access_token = refreshResult.access_token;
    tokenData.expires_at = Date.now() + (refreshResult.expires_in || 3600) * 1000;
    if (refreshResult.refresh_token) tokenData.refresh_token = refreshResult.refresh_token;
    fs.writeFileSync(tokenPath, JSON.stringify(tokenData, null, 2));
  } else {
    return R('❌ Token de Spotify expirado. Ejecuta: `bash scripts/spotify_auth.sh`');
  }
}

// Fetch all followed shows (paginated)
const allShows = [];
let nextUrl = '/me/shows?limit=50';
while (nextUrl) {
  const res = await spotifyGet(nextUrl.replace('https://api.spotify.com/v1', ''), tokenData.access_token);
  if (res.status === 401) return R('❌ Token de Spotify inválido. Ejecuta: `bash scripts/spotify_auth.sh`');
  if (res.status !== 200) return R(`❌ Error Spotify API: ${res.status}`);
  (res.body.items || []).forEach(item => {
    if (item.show) allShows.push(item.show);
  });
  const next = res.body.next;
  nextUrl = next ? next.replace('https://api.spotify.com/v1', '') : null;
}

if (!allShows.length) return R('ℹ️ No sigues ningún podcast en Spotify.');

const pool = new Pool({
  host: $env.POSTGRES_HOST || 'postgres_shared',
  port: parseInt($env.POSTGRES_PORT || '5432'),
  database: $env.POSTGRES_DB || 'homelab',
  user: $env.POSTGRES_USER,
  password: $env.POSTGRES_PASSWORD,
});

let added = 0, existing = 0;
try {
  for (const show of allShows) {
    // Upsert into spotify_shows
    await pool.query(
      `INSERT INTO podcasts.spotify_shows (show_id, name, description, synced_at)
       VALUES ($1, $2, $3, NOW())
       ON CONFLICT (show_id) DO UPDATE SET name=$2, description=$3, synced_at=NOW()`,
      [show.id, show.name, (show.description || '').slice(0, 500)]
    );
    // Check if already in episodes
    const { rows } = await pool.query(
      `SELECT id FROM podcasts.episodes
       WHERE podcasts.norm(show_name) = podcasts.norm($1) AND status != 'dismissed'
       LIMIT 1`,
      [show.name]
    );
    if (rows.length === 0) {
      const newId = 'sp_' + show.id.slice(0, 12) + '_' + Date.now().toString(36);
      await pool.query(
        `INSERT INTO podcasts.episodes (id, source, title, show_name, url, status)
         VALUES ($1, 'podcast', $2, $3, $4, 'pending')
         ON CONFLICT (id) DO NOTHING`,
        [newId, `Podcast: ${show.name}`, show.name, `https://open.spotify.com/show/${show.id}`]
      );
      added++;
    } else {
      existing++;
    }
  }
  await pool.end();
  return R(`🔄 Sincronizado: ${added} nuevo${added !== 1 ? 's' : ''} podcast${added !== 1 ? 's' : ''} añadido${added !== 1 ? 's' : ''}, ${existing} ya existían.`);
} catch (err) {
  await pool.end().catch(() => {});
  return R(`❌ Error DB: ${err.message}`);
}

