const { Pool } = require('pg');
const pool = new Pool({
  host: $env.POSTGRES_HOST || 'postgres_shared',
  port: parseInt($env.POSTGRES_PORT || '5432'),
  database: $env.POSTGRES_DB || 'homelab',
  user: $env.POSTGRES_USER,
  password: $env.POSTGRES_PASSWORD,
});

const inp = $input.first().json;
const text = inp.text || '';
const urlMatch = text.match(/https?:\/\/[^\s]+/);
const url = urlMatch ? urlMatch[0].replace(/[.,;!?]+$/, '') : '';

if (!url) {
  await pool.end().catch(()=>{});
  return [{json: {reply_text: '❌ No encontré una URL válida.'}}];
}

let source = 'article';
let epId = null;
let title = url;
let showName = '';
let durationMin = null;

// YouTube
const ytMatch = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
if (ytMatch) {
  source = 'youtube';
  epId = 'yt_' + ytMatch[1];
  try {
    const apiUrl = `https://www.googleapis.com/youtube/v3/videos?part=snippet,contentDetails&id=${ytMatch[1]}&key=${$env.YOUTUBE_API_KEY}`;
    const res = await fetch(apiUrl);
    const data = await res.json();
    if (data.items && data.items[0]) {
      const it = data.items[0];
      title = it.snippet.title;
      showName = it.snippet.channelTitle;
      const dur = it.contentDetails && it.contentDetails.duration ? it.contentDetails.duration : '';
      const dm = dur.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
      if (dm) durationMin = Math.round((parseInt(dm[1]||0)*60) + parseInt(dm[2]||0) + parseInt(dm[3]||0)/60);
    }
  } catch(e) {}
} else {
  // Generic URL — try Open Graph
  const b64 = Buffer.from(url).toString('base64').slice(0, 24).replace(/[^a-zA-Z0-9]/g,'_');
  epId = 'url_' + b64;
  try {
    const res = await fetch(url, {
      headers: {'User-Agent': 'Mozilla/5.0'},
      signal: AbortSignal.timeout(6000)
    });
    const html = await res.text();
    const ogTitle = html.match(/<meta[^>]+property="og:title"[^>]+content="([^"]+)"/i) ||
                    html.match(/<meta[^>]+content="([^"]+)"[^>]+property="og:title"/i);
    const htmlTitle = html.match(/<title[^>]*>([^<]+)<\/title>/i);
    if (ogTitle) title = ogTitle[1].trim();
    else if (htmlTitle) title = htmlTitle[1].trim();
    const ogSite = html.match(/<meta[^>]+property="og:site_name"[^>]+content="([^"]+)"/i) ||
                   html.match(/<meta[^>]+content="([^"]+)"[^>]+property="og:site_name"/i);
    if (ogSite) showName = ogSite[1].trim();
  } catch(e) {}
}

try {
  await pool.query(
    `INSERT INTO podcasts.episodes (id, source, title, show_name, url, status, listened_at, created_at)
     VALUES ($1, $2, $3, $4, $5, 'listened', NOW(), NOW())
     ON CONFLICT (id) DO UPDATE SET
       status = 'listened',
       listened_at = COALESCE(podcasts.episodes.listened_at, NOW()),
       title = EXCLUDED.title,
       show_name = EXCLUDED.show_name`,
    [epId, source, title, showName, url]
  );
  await pool.end();
  const icon = source === 'youtube' ? '📺' : source === 'podcast' ? '🎙️' : '📰';
  const dur = durationMin ? ' · ' + durationMin + ' min' : '';
  return [{json: {reply_text: '✅ *Guardado como escuchado*\n\n' + icon + ' *' + title + '*' + (showName ? '\n📡 ' + showName : '') + dur + '\n\n_Añadido a tu historial para mejorar tus recomendaciones._'}}];
} catch(e) {
  await pool.end().catch(()=>{});
  return [{json: {reply_text: '❌ Error guardando: ' + e.message}}];
}
